  def icon_list, do: @icons

  attr(
    :size,
    :string,
    doc: "Size of the icon. According to the tailwind documentation in `w-` and `h-`.",
    default: "4"
  )

  attr(
    :fill,
    :string,
    doc: "Color of the icon. According to the defined tailwind colors.",
    default: "fill-current"
  )

  attr(
    :stroke,
    :string,
    doc: "Color of the icon. According to the defined tailwind colors.",
    default: "stroke-current"
  )

  attr(
    :align,
    :string,
    doc: "Vertical alignment of the icon",
    default: "align-text-top"
  )

  attr(
    :name,
    :string,
    doc: "Name of the icon",
    values: @icons
  )

  @doc """
    Lister les icônes utilisés dans les applications Tag-IP.

  ## Usage

    <.waw_icons name="home" size="3" stroke="none" />
  """

